import numpy as np,time
from scipy.linalg import eig,eigvals
from scipy.linalg.lapack import dgeev
sizes=list(range(2,11,2)); N=1000

def ref(A):
    w,v=np.linalg.eig(A)
    i=np.abs(w).argmax(); return w[i],v[:,i]

def s1(A):
    w,v=eig(A,left=False,right=True,overwrite_a=False,check_finite=False)
    i=np.abs(w).argmax(); return w[i],v[:,i]

def s2(A):
    wr,wi,vl,vr,info=dgeev(A,compute_vl=0,compute_vr=1,overwrite_a=0)
    if info!=0: raise RuntimeError(info)
    w=wr+1j*wi
    i=np.abs(w).argmax()
    if wi[i]==0:
        x=vr[:,i].astype(np.complex128)
    elif wi[i]>0:
        x=vr[:,i]+1j*vr[:,i+1]
    else:
        x=vr[:,i-1]-1j*vr[:,i]
    return w[i],x

def s3(A):
    w=eigvals(A,overwrite_a=False,check_finite=False)
    i=np.abs(w).argmax(); lam=w[i]
    # recover vector from dgeev? impossible
    wr,wi,vl,vr,info=dgeev(A,compute_vl=0,compute_vr=1,overwrite_a=0)
    w2=wr+1j*wi; j=np.argmin(np.abs(w2-lam))
    if wi[j]==0: x=vr[:,j].astype(np.complex128)
    elif wi[j]>0: x=vr[:,j]+1j*vr[:,j+1]
    else: x=vr[:,j-1]-1j*vr[:,j]
    return lam,x

# correctness
for name,fn in [('ref',ref),('s1',s1),('s2',s2),('s3',s3)]:
  ok=True
  for n in sizes:
    for _ in range(100):
      A=np.random.normal(size=(n,n))
      lam,x=fn(A)
      if not np.allclose(A@x,lam*x):
        ok=False; break
    if not ok: break
  print(name,'ok',ok)

for n in sizes:
    mats=[np.random.normal(size=(n,n)).astype(np.float64) for _ in range(N)]
    print('n',n)
    for name,fn in [('ref',ref),('s1',s1),('s2',s2),('s3',s3)]:
        ts=[]
        for A in mats:
            t0=time.perf_counter(); fn(A); ts.append(time.perf_counter()-t0)
        print(name,np.median(ts))
